import itertools

def probability_of_n_heads(coin_probs, n):
    total_prob = 0
    for combination in itertools.combinations(coin_probs, n):
        prob = 1
        for p in combination:
            prob *= p
        for p in set(coin_probs) - set(combination):
            prob *= (1 - p)
        total_prob += prob
    return total_prob

def greedy_selection(coin_probs, n):
    sorted_coins = sorted(coin_probs, reverse=True)
    return sorted_coins[:n]

def exhaustive_selection(coin_probs, n):
    best_prob = 0
    best_combination = []
    for combination in itertools.combinations(coin_probs, n):
        prob = probability_of_n_heads(combination, n)
        if prob > best_prob:
            best_prob = prob
            best_combination = combination
    return best_combination

def dynamic_programming_selection(coin_probs, n):
    dp = [[0] * (n + 1) for _ in range(len(coin_probs) + 1)]
    for i in range(1, len(coin_probs) + 1):
        for j in range(1, n + 1):
            dp[i][j] = dp[i - 1][j]
            if j > 0:
                dp[i][j] = max(dp[i][j], dp[i - 1][j - 1] * coin_probs[i - 1])
    return dp[len(coin_probs)][n]

