import itertools
import numpy as np

def probability_of_n_heads(coin_probs, n):
    total_prob = 0
    for combination in itertools.combinations(coin_probs, n):
        prob = np.prod(combination) * np.prod([1 - p for p in coin_probs if p not in combination])
        total_prob += prob
    return total_prob

def greedy_selection(coin_probs, n):
    sorted_probs = sorted(coin_probs, reverse=True)
    return sorted_probs[:n]

def dynamic_programming_selection(coin_probs, n):
    dp = np.zeros((n + 1, len(coin_probs) + 1))
    for i in range(1, len(coin_probs) + 1):
        for j in range(n + 1):
            dp[j][i] = dp[j][i - 1]
            if j > 0:
                dp[j][i] = max(dp[j][i], dp[j - 1][i - 1] + coin_probs[i - 1])
    selected_coins = []
    j = n
    for i in range(len(coin_probs), 0, -1):
        if dp[j][i] != dp[j][i - 1]:
            selected_coins.append(coin_probs[i - 1])
            j -= 1
    return selected_coins

def exhaustive_selection(coin_probs, n):
    return max(itertools.combinations(coin_probs, n), key=probability_of_n_heads)

def compare_methods(coin_probs, n):
    greedy_coins = greedy_selection(coin_probs, n)
    dp_coins = dynamic_programming_selection(coin_probs, n)
    exhaustive_coins = exhaustive_selection(coin_probs, n)

    greedy_prob = probability_of_n_heads(greedy_coins, n)
    dp_prob = probability_of_n_heads(dp_coins, n)
    exhaustive_prob = probability_of_n_heads(exhaustive_coins, n)

    return {
        'greedy': (greedy_coins, greedy_prob),
        'dynamic_programming': (dp_coins, dp_prob),
        'exhaustive': (exhaustive_coins, exhaustive_prob)
    }

